async function lightning_newaddress(data = {}) {
  const nodeId = data.userId || 'node4'
  try {
    // Request a bech32 (SegWit) address, which is standard
    const { stdout } = await lnRpc(nodeId, 'newaddr', ['bech32'])
    const parsed = JSON.parse(stdout)

    // The address is in the 'bech32' field
    if (!parsed.bech32) {
      throw new Error('Could not get bech32 address from node.');
    }
    return { status: 'success', data: parsed.bech32 }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

