async function validate_ln_payment(data = {}) {
  const { payment_hash, amount_msat } = data
  const nodeId = data.userId || 'node4'
  if (!payment_hash) return { status: 'error', error: 'payment_hash is required' }

  try {
    const { stdout } = await lnRpc(nodeId, 'listinvoices', [`payment_hash=${payment_hash}`])
    const parsed = JSON.parse(stdout)

    if (!parsed.invoices || parsed.invoices.length === 0) {
      return { status: 'error', error: 'Invoice not found' }
    }

    const invoice = parsed.invoices[0]

    if (invoice.status !== 'paid') {
      return { status: 'pending', data: invoice }
    }

    if (amount_msat && invoice.amount_received_msat !== parseInt(amount_msat, 10)) {
      return { status: 'error', error: `Amount mismatch: expected ${amount_msat}, got ${invoice.amount_received_msat}` }
    }

    return { status: 'success', data: invoice }

  } catch (err) {
    return { status: 'error', error: err.message }
  }
}
async function create_ln_invoice(data = {}) {
  const { amount_msat, description, expiry } = data
  const nodeId = data.userId || 'node4' // Use userId as the nodeId

  if (!amount_msat || !description) {
    return { status: 'error', error: 'amount_msat and description are required' }
  }

  const label = data.label || `flamingo-${nodeId}-${Date.now()}`

  const params = [
    amount_msat,
    `"${label}"`,
    `"${description}"`
  ]

  if (expiry) {
    params.push(expiry) // Add expiry time in seconds, e.g., 3600 for 1 hour
  }

  try {
    const { stdout } = await lnRpc(nodeId, 'invoice', params)
    const parsed = JSON.parse(stdout)

    return { status: 'success', data: parsed }

  } catch (err) {
    return { status: 'error', error: err.message }
  }
}
async function pay_ln_invoice(data = {}) {
  const { invoice_string } = data
  const nodeId = data.userId || 'node4'
  if (!invoice_string) return { status: 'error', error: 'invoice_string is required' }

  try {
    const { stdout } = await lnRpc(nodeId, 'pay', [invoice_string])
    const parsed = JSON.parse(stdout)

    return { status: 'pending', data: parsed }

  } catch (err) {
    try {
      const parsedError = JSON.parse(err.message);
      return { status: 'error', error: parsedError.message || err.message.trim() }
    } catch (e) {
      return { status: 'error', error: err.message.trim() }
    }
  }
}

async function get_ln_payment_status(data = {}) {
  const { payment_hash } = data
  const nodeId = data.userId || 'node4'
  if (!payment_hash) return { status: 'error', error: 'payment_hash is required' }

  try {
    const { stdout } = await lnRpc(nodeId, 'listsendpays', [`payment_hash=${payment_hash}`])
    const parsed = JSON.parse(stdout)

    if (!parsed.payments || parsed.payments.length === 0) {
      return { status: 'error', error: 'Payment not found' }
    }

    const payment = parsed.payments[0]

    if (payment.status === 'complete') {
      return { status: 'success', data: payment }
    }

    if (payment.status === 'failed') {
      return { status: 'error', error: 'Payment failed', data: payment }
    }

    return { status: 'pending', data: payment }

  } catch (err) {
    return { status: 'error', error: err.message }
  }
}


