async function validate_btc_payment(data = {}) {
  const { tx_id, amount, min_conf } = data
  if (!tx_id) return { status: 'error', error: 'tx_id is required' }

  try {
    const { stdout } = await btcRpc('gettransaction', [tx_id, true]) // true for verbose
    const tx = JSON.parse(stdout)

    const confirmations = tx.confirmations || 0
    if (confirmations < (min_conf || 1)) {
      return { status: 'pending', data: { confirmations, tx } }
    }

    const receivedAmount = (tx.details || [])
      .filter(d => d.category === 'receive')
      .reduce((acc, d) => acc + d.amount, 0)

    if (amount && receivedAmount !== parseFloat(amount)) {
      return { status: 'error', error: `Amount mismatch: expected ${amount}, got ${receivedAmount}` }
    }

    return { status: 'success', data: { confirmations, receivedAmount, tx } }

  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

