// Helper
async function _get_node_uri(nodeId, fallbackPort) {
  try {
    const { stdout } = await lnRpc(nodeId, 'getinfo')
    const info = JSON.parse(stdout)

    let host = '127.0.0.1'
    let port = fallbackPort
    if (info.binding && info.binding.length > 0) {
      const ipv4 = info.binding.find(b => b.type === 'ipv4')
      if (ipv4) {
        host = ipv4.address
        port = ipv4.port
        console.log(`Found dynamic binding for ${nodeId}: ${host}:${port}`)
      }
    }
    return {
      pubkey: info.id,
      address: `${info.id}@${host}:${port}`
    }
  } catch (err) {
    console.error(`Failed to get info for ${nodeId}:`, err.message)
    throw new Error(`Could not find node ${nodeId}. Is it running?`)
  }
}
async function open_channel_with_default_peer(data = {}) {
  const userId = data.userId || 'node4'
  const amount_sats = data.amount_sats || 200000

  try {
    console.log(`🦩 Initiating Flamingo Default Connection for ${userId}...`)

    const hub = await _get_node_uri('node5', 9736)

    try {
      await lnRpc(userId, 'connect', [hub.address])
    } catch (e) {
      if (!e.message.includes('already connected')) throw e
    }

    const { stdout } = await lnRpc(userId, 'fundchannel', [hub.pubkey, `${amount_sats}sat`])
    const parsed = JSON.parse(stdout)

    return {
      status: 'success',
      data: {
        message: '✅ Connected to Flamingo Hub',
        txid: parsed.txid,
        channel_id: parsed.channel_id,
        hub_alias: 'Flamingo Core',
        note: 'Please mine blocks to confirm this channel.'
      }
    }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

// ROUTING SETUP 
async function admin_setup_hub_routing(data = {}) {
  const log = (msg) => console.log(`[Setup] ${msg}`)

  try {
    log('⚙️ Setting up Backend Routes (Hub -> Merchant)...')

    const merchant = await _get_node_uri('node6', 9737)

    try { await lnRpc('node5', 'connect', [merchant.address]) } catch (e) { }

    const { stdout: fundList } = await lnRpc('node5', 'listfunds')
    const existing = JSON.parse(fundList).channels || []
    const hasChannel = existing.find(c => c.peer_id === merchant.pubkey)
    let txid = null

    if (!hasChannel) {
      log('Opening channel N5 -> N6...')
      const { stdout } = await lnRpc('node5', 'fundchannel', [merchant.pubkey, '5000000sat'])
      const parsed = JSON.parse(stdout)
      txid = parsed.txid
      log(`Channel funded! TXID: ${txid}`)
    } else {
      log('Channel exists. Checking status...')
      txid = hasChannel.funding_txid
    }

    const { stdout: checkList } = await lnRpc('node5', 'listfunds')
    const channels = JSON.parse(checkList).channels || []
    const target = channels.find(c => c.peer_id === merchant.pubkey)

    const state = target ? target.state : 'UNKNOWN'
    if (state !== 'CHANNELD_NORMAL') {
      log(`Channel state is ${state}. Waiting for user to mine blocks.`)
      return {
        status: 'success',
        data: {
          message: '⏳ Channel Created. Waiting for Confirmation.',
          note: `State: ${state}. Please click "Mine Blocks" manually (6 blocks) to activate.`,
          txid: txid
        }
      }
    }
    log('Channel is active. Refreshing gossip...')
    try {
      await lnRpc('node5', 'disconnect', [merchant.pubkey])
      await new Promise(r => setTimeout(r, 1000))
      await lnRpc('node5', 'connect', [merchant.address])
    } catch (e) { }
    try {
      const hub = await _get_node_uri('node5', 9736)
      await lnRpc('node4', 'connect', [hub.address])
    } catch (e) { }

    return {
      status: 'success',
      data: {
        message: '✅ Route Established.',
        note: 'Channel is NORMAL and Active.',
        txid: txid
      }
    }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}
// VERIFY REVENUE 
async function verify_revenue_model(data = {}) {
  const amount_msat = data.amount_msat || 10000

  try {
    console.log('🕵️ Verifying Business Model...')

    const label = `test-rev-${Date.now()}`
    const invCmd = await lnRpc('node6', 'invoice', [amount_msat, label, '"Test Payment"'])
    const invoice = JSON.parse(invCmd.stdout)
    const bolt11 = invoice.bolt11
    const target_hash = invoice.payment_hash

    let receipt = null
    for (let i = 1; i <= 5; i++) {
      try {
        console.log(`   Payment Attempt ${i}/5...`)
        const payCmd = await lnRpc('node4', 'pay', [bolt11])
        receipt = JSON.parse(payCmd.stdout)
        break
      } catch (e) {
        console.log(`   Attempt ${i} failed: ${e.message.substring(0, 50)}...`)
        if (i === 5) throw new Error(`Payment failed after 5 attempts. Route not ready? Error: ${e.message}`)
        await new Promise(r => setTimeout(r, 2000))
      }
    }
    await new Promise(resolve => setTimeout(resolve, 3000));

    const fwCmd = await lnRpc('node5', 'listforwards')
    const allForwards = JSON.parse(fwCmd.stdout).forwards || []
    const recentSettled = allForwards.filter(f => f.status === 'settled').slice(-5);

    const match = recentSettled.find(f => f.payment_hash === target_hash) ||
      recentSettled.find(f => f.fee_msat > 0 && f.out_msat === parseInt(amount_msat))

    if (!match) {
      return {
        status: 'warning',
        data: {
          message: 'Payment success, but log not found.',
          debug: { recent_logs: recentSettled },
          receipt
        }
      }
    }

    return {
      status: 'success',
      data: {
        verification: 'PASSED',
        payment_route: 'Node4 -> Node5 -> Node6',
        fee_earned_msat: match.fee_msat,
        hub_business_logic_verified: true
      }
    }

  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

// CLEANUP RESET 
async function admin_reset_world() {
  const logs = []
  const log = (msg) => {
    console.log(msg)
    logs.push(msg)
  }

  try {
    log('🧨 RESETTING WORLD: Closing & Disconnecting...')

    const cleanupNode = async (nodeId) => {

      const { stdout } = await lnRpc(nodeId, 'listfunds')
      const channels = JSON.parse(stdout).channels || []

      log(`[${nodeId}] Found ${channels.length} channel records.`)
      let actionCount = 0

      for (const c of channels) {
        const shortId = c.channel_id.substring(0, 10)
        const peerId = c.peer_id
        const state = c.state

        if (state === 'CHANNELD_NORMAL' || state === 'CHANNELD_AWAITING_LOCKIN') {
          try {
            await lnRpc(nodeId, 'close', [c.channel_id])
            log(`    ✅ Sent CLOSE for ${shortId} (was ${state})`)
            actionCount++
          } catch (e) {
            log(`    ❌ Close failed ${shortId}: ${e.message}`)
          }
        }
        else if (state === 'ONCHAIN') {
          try {
            await lnRpc(nodeId, 'disconnect', [peerId])
            log(`    ✂️ Disconnected peer for dead channel ${shortId}`)
            actionCount++
          } catch (e) {
          }
        }
      }
      return actionCount
    }

    await cleanupNode('node4')
    await cleanupNode('node5')

    log(`Mining 10 blocks to bury dead channels...`)
    await btc_mine_blocks_regtest({ num_blocks: 10 })

    return {
      status: 'success',
      data: {
        message: `Cleanup Complete.`,
        logs: logs
      }
    }
  } catch (err) {
    return { status: 'error', error: err.message, logs }
  }
}
// LIQUIDITY MONITOR 
async function get_liquidity_report(data = {}) {
  const nodeId = data.userId || 'node4'

  try {
    const { stdout } = await lnRpc(nodeId, 'listfunds')
    const parsed = JSON.parse(stdout)

    let outbound = 0
    let inbound = 0
    let total_capacity = 0

    const channels = (parsed.channels || []).filter(c => c.state === 'CHANNELD_NORMAL')

    channels.forEach(c => {
      const cap = c.amount_msat
      const ours = c.our_amount_msat
      const theirs = cap - ours

      outbound += ours
      inbound += theirs
      total_capacity += cap
    })

    const outSats = Math.floor(outbound / 1000)
    const inSats = Math.floor(inbound / 1000)
    const totalSats = Math.floor(total_capacity / 1000)

    let status = 'HEALTHY'
    let message = 'Liquidity is balanced.'
    let action_required = false

    if (totalSats === 0) {
      status = 'EMPTY'
      message = 'No active channels. You are disconnected.'
      action_required = true
    } else if (inSats < 50000) {
      status = 'LOW_INBOUND'
      message = 'You have low receiving capacity.'
      action_required = true
    } else if (outSats < 10000) {
      status = 'LOW_OUTBOUND'
      message = 'You have low spending balance.'
      action_required = true
    }

    return {
      status: 'success',
      data: {
        outbound_sats: outSats,
        inbound_sats: inSats,
        total_capacity_sats: totalSats,
        active_channels: channels.length,
        health: {
          status: status,
          message: message,
          action_required: action_required
        }
      }
    }

  } catch (err) {
    return { status: 'error', error: err.message }
  }
}


//Simulates Hub opening channel to User
async function request_inbound_liquidity(data = {}) {
  const userId = data.userId || 'node4'
  const amount_sats = data.amount_sats || 1000000

  try {
    console.log(`🔧 Automagic: ${userId} requesting inbound liquidity...`)

    const userParams = await lnRpc(userId, 'getinfo')
    const userInfo = JSON.parse(userParams.stdout)
    let userHost = '127.0.0.1'
    let userPort = 9735
    if (userInfo.binding && userInfo.binding.length > 0) {
      const ipv4 = userInfo.binding.find(b => b.type === 'ipv4')
      if (ipv4) { userHost = ipv4.address; userPort = ipv4.port }
    }
    const userUri = `${userInfo.id}@${userHost}:${userPort}`

    const hubId = 'node5'
    try {
      await lnRpc(hubId, 'connect', [userUri])
    } catch (e) { }

    const { stdout } = await lnRpc(hubId, 'fundchannel', [userInfo.id, `${amount_sats}sat`])
    const parsed = JSON.parse(stdout)

    await btc_mine_blocks_regtest({ num_blocks: 6 })

    await new Promise(r => setTimeout(r, 2000))

    return {
      status: 'success',
      data: {
        message: '✅ Flamingo Hub opened a channel to you.',
        inbound_added: amount_sats,
        txid: parsed.txid,
        note: 'You can now receive payments!'
      }
    }

  } catch (err) {
    return { status: 'error', error: `Liquidity Service Failed: ${err.message}` }
  }
}
// Helper: Fetch and Normalize Data
async function _fetch_unified_history(userId) {
  const history = []
  try {
    const { stdout } = await btcRpc('listtransactions', ['"*"', 100, 0, true])
    const btcTxs = JSON.parse(stdout)

    btcTxs.forEach(tx => {
      if (tx.category === 'move') return

      history.push({
        type: 'BTC',
        id: tx.txid,
        direction: tx.category === 'receive' ? 'IN' : 'OUT',
        amount_msat: Math.abs(tx.amount * 100000000 * 1000),
        status: (tx.confirmations > 0) ? 'CONFIRMED' : 'PENDING',
        timestamp: tx.time,
        note: tx.label || tx.address,
        fee_msat: tx.fee ? Math.abs(tx.fee * 100000000 * 1000) : 0
      })
    })
  } catch (e) {
    console.error('Error fetching BTC history:', e.message)
  }
  try {
    const { stdout } = await lnRpc(userId, 'listinvoices')
    const invoices = JSON.parse(stdout).invoices || []

    invoices.forEach(inv => {
      if (inv.status === 'paid') {
        history.push({
          type: 'LN',
          id: inv.payment_hash,
          direction: 'IN',
          amount_msat: inv.amount_received_msat,
          status: 'CONFIRMED',
          timestamp: inv.paid_at,
          note: inv.description,
          fee_msat: 0
        })
      }
    })
  } catch (e) {
    console.error('Error fetching LN invoices:', e.message)
  }

  try {
    const { stdout } = await lnRpc(userId, 'listpays')
    const payments = JSON.parse(stdout).pays || []

    payments.forEach(pay => {
      if (pay.status === 'complete') {
        history.push({
          type: 'LN',
          id: pay.payment_hash,
          direction: 'OUT',
          amount_msat: pay.amount_msat,
          status: 'CONFIRMED',
          timestamp: pay.created_at,
          note: pay.description || 'Lightning Payment',
          fee_msat: (pay.amount_sent_msat - pay.amount_msat) || 0
        })
      }
    })
  } catch (e) {
    console.error('Error fetching LN payments:', e.message)
  }
  return history.sort((a, b) => b.timestamp - a.timestamp)
}

async function log_transaction(data = {}) {
  return {
    status: 'success',
    message: 'Transaction logged to Blockchain/Node memory automatically.'
  }
}

async function get_transaction_history(data = {}) {
  const userId = data.userId || 'node4'
  const limit = data.limit || 50

  try {
    const fullHistory = await _fetch_unified_history(userId)
    const sliced = fullHistory.slice(0, limit)

    return { status: 'success', data: sliced }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

async function get_transaction_summary(data = {}) {
  const userId = data.userId || 'node4'

  try {
    const history = await _fetch_unified_history(userId)

    let total_in = 0
    let total_out = 0
    let fees = 0

    history.forEach(tx => {
      if (tx.direction === 'IN') total_in += tx.amount_msat
      if (tx.direction === 'OUT') total_out += tx.amount_msat
      fees += (tx.fee_msat || 0)
    })

    return {
      status: 'success',
      data: {
        total_received_msat: total_in,
        total_sent_msat: total_out,
        total_fees_paid_msat: fees,
        net_balance_msat: total_in - total_out,
        tx_count: history.length
      }
    }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

async function get_daily_transactions(data = {}) {
  const userId = data.userId || 'node4'
  const targetDate = data.date

  if (!targetDate) return { status: 'error', error: 'Date required (YYYY-MM-DD)' }

  try {
    const history = await _fetch_unified_history(userId)

    const filtered = history.filter(tx => {
      const dateStr = new Date(tx.timestamp * 1000).toISOString().split('T')[0]
      return dateStr === targetDate
    })

    return { status: 'success', data: filtered }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

async function get_transaction_type(data = {}) {
  const { tx_id } = data
  if (!tx_id) return { status: 'error', error: 'tx_id required' }

  try {
    const history = await _fetch_unified_history(data.userId || 'node4')
    const found = history.find(t => t.id === tx_id)

    if (!found) return { status: 'error', error: 'Transaction not found in node history' }

    return { status: 'success', data: { type: found.type, details: found } }
  } catch (err) {
    return { status: 'error', error: err.message }
  }

}

async function decode_ln_invoice(data = {}) {
  const { invoice_string } = data
  if (!invoice_string) return { status: 'error', error: 'Invoice string required' }
  const nodeId = data.userId || 'node4'

  try {
    const { stdout } = await lnRpc(nodeId, 'decode', [invoice_string])
    const decoded = JSON.parse(stdout)

    const knownNodes = ['node4', 'node5', 'node6']
    for (const n of knownNodes) {
      try {
        const info = await lnRpc(n, 'getinfo')
        const id = JSON.parse(info.stdout).id
        if (id === decoded.payee) {
          decoded._alias = n.charAt(0).toUpperCase() + n.slice(1)
          break
        }
      } catch (e) { }
    }

    return { status: 'success', data: decoded }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

async function validate_btc_address(data = {}) {
  const { address } = data
  if (!address) return { status: 'error', error: 'Address required' }

  try {
    const { stdout } = await btcRpc('validateaddress', [address])
    const res = JSON.parse(stdout)
    return { status: 'success', data: res }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

async function sign_message(data = {}) {
  const { message } = data
  if (!message) return { status: 'error', error: 'Message required' }
  const nodeId = data.userId || 'node4'

  try {
    const { stdout } = await lnRpc(nodeId, 'signmessage', [message])
    return { status: 'success', data: JSON.parse(stdout) }
  } catch (err) {
    return { status: 'error', error: err.message }
  }
}

async function verify_message(data = {}) {
  const { message, signature } = data
  if (!message || !signature) return { status: 'error', error: 'Message and Signature required' }
  // Any node can verify a signature, doesn't matter which one we use. Use node4 by default.
  const verifierNode = 'node4'

  try {
    const { stdout } = await lnRpc(verifierNode, 'checkmessage', [message, signature])
    const result = JSON.parse(stdout)
    if (result.verified) {
      const knownNodes = ['node4', 'node5', 'node6']
      for (const n of knownNodes) {
        try {
          const info = await lnRpc(n, 'getinfo')
          const id = JSON.parse(info.stdout).id
          if (id === result.pubkey) {
            result._alias = n.charAt(0).toUpperCase() + n.slice(1)
            break
          }
        } catch (e) { }
      }
    }

    return { status: 'success', data: result }
  } catch (err) {
    return { status: 'success', data: { verified: false, raw_error: err.message } }
  }
}
// -----------------------------------------------------------------------------
// 🔄 WebSocket handler
// -----------------------------------------------------------------------------
async function handleMessage(msg, ws, server) {
  const [by, to, mid] = msg.head || []
  const intent = msg.type
  const data = msg.data

  console.log(`📩 Received from ${by}:`, intent, data || '')

  if (intent === 'daemon-stop') {
    console.log('🚨 Stopping backend daemon as requested...')
  }

  const actions = {
    'lightning-getinfo': lightning_getinfo,
    'lightning-listfunds': lightning_listfunds_raw,
    'bitcoin-newaddress': bitcoin_newaddress,

    'lightning_newaddress': lightning_newaddress,


    'get_btc_balance': get_btc_balance,
    'get_ln_balance': get_ln_balance,
    'sync_wallet_balances': sync_wallet_balances,
    'convert_btc_to_usd': convert_btc_to_usd,
    'estimate_btc_fee': estimate_btc_fee,
    'get_tx_details_from_btcnode': get_tx_details_from_btcnode,
    'get_tx_details_from_lnnode': get_tx_details_from_lnnode,
    'list_btc_transactions': list_btc_transactions,
    'list_ln_invoices': list_ln_invoices,

    'decode_ln_invoice': decode_ln_invoice,
    'validate_btc_address': validate_btc_address,
    'sign_message': sign_message,
    'verify_message': verify_message,


    'validate_btc_payment': validate_btc_payment,
    'validate_ln_payment': validate_ln_payment,
    'send_btc_onchain': send_btc_onchain,
    'create_ln_invoice': create_ln_invoice,
    'pay_ln_invoice': pay_ln_invoice,
    'get_ln_payment_status': get_ln_payment_status,
    'btc_mine_blocks_regtest': btc_mine_blocks_regtest,

    'list_peers': list_peers,
    'connect_node': connect_node,
    'fund_channel': fund_channel,

    'open_channel_flamingo': open_channel_with_default_peer,
    'admin_setup_hub': admin_setup_hub_routing,
    'verify_revenue': verify_revenue_model,
    'admin_reset_world': admin_reset_world,

    'get_liquidity_report': get_liquidity_report,
    'request_inbound_liquidity': request_inbound_liquidity,


    'log_transaction': log_transaction,
    'get_transaction_history': get_transaction_history,
    'get_transaction_summary': get_transaction_summary,
    'get_daily_transactions': get_daily_transactions,
    'get_transaction_type': get_transaction_type
  }

  const fn = actions[intent]
  if (!fn) {
    return ws.send(JSON.stringify({
      head: ['backend', by, mid],
      type: `${intent}:response`,
      data: { status: 'error', error: `Unknown action: ${intent}` }
    }))
  }

  const payload = await fn(data)

  ws.send(JSON.stringify({
    head: ['backend', by, mid],
    type: `${intent}:response`,
    data: payload
  }))
}

// -----------------------------------------------------------------------------
// 🚀 WebSocket server setup
// -----------------------------------------------------------------------------
const wss = new WebSocketServer({ port: Number(WS_PORT) })
console.log(`🚀 Backend daemon listening on ws://localhost:${WS_PORT}`)

wss.on('connection', (ws, req) => {
  console.log('client connected:', req.socket.remoteAddress)
  ws.on('message', async (raw) => {
    try {
      const msg = JSON.parse(raw.toString())
      await handleMessage(msg, ws, wss)
    } catch (err) {
      console.error('Message error:', err.message)
      ws.send(JSON.stringify({ type: 'error', data: { error: err.message } }))
    }
  })
  ws.on('close', () => console.log('client disconnected'))
})
